mapper.select:
/* selectSurveyListWithFilter */ SELECT ts.srvy_oid, ts.srvy_ttl , ts.srvy_bgng_dt, ts.srvy_end_dt , COUNT(tsq.srvy_qitem_oid) AS qst_cnt , CASE WHEN CURDATE() < ts.srvy_bgng_dt THEN 'WAIT' WHEN CURDATE() BETWEEN ts.srvy_bgng_dt AND ts.srvy_end_dt THEN 'ING' WHEN CURDATE() > ts.srvy_end_dt THEN 'END' END AS stts , (IF(ts.atch1_file_oid IS NOT NULL, 1, 0) + IF(ts.atch2_file_oid IS NOT NULL, 1, 0)) AS file_cnt FROM ${schema}.srvy ts LEFT JOIN ${schema}.srvy_qitem tsq ON tsq.srvy_oid = ts.srvy_oid AND tsq.srvy_qitem_type IS NOT NULL WHERE ts.srvy_stts NOT IN ('DEL','REG') AND ts.srvy_type = 'COMMON'
AND ts.srvy_oid = #{srvyOid}
AND ts.srvy_ttl LIKE CONCAT('%', #{keyword} ,'%')
GROUP BY ts.srvy_oid, ts.srvy_ttl , ts.srvy_bgng_dt, ts.srvy_end_dt , CASE WHEN CURDATE() < ts.srvy_bgng_dt THEN 'WAIT' WHEN CURDATE() BETWEEN ts.srvy_bgng_dt AND ts.srvy_end_dt THEN 'ING' WHEN CURDATE() > ts.srvy_end_dt THEN 'END' END ORDER BY ts.srvy_oid DESC

	/* selectSurveyParticipatedYn */
    SELECT
    	COUNT(*)
    FROM
    	${schema}.srvy_rspdnt
    WHERE
    	srvy_oid = #{srvyOid}
		AND ip_addr = #{ipAddr}
		AND cmpl_yn = 'Y'

/* selectSurveyDetail */ SELECT srvy_oid, srvy_ttl, srvy_bgng_dt, srvy_end_dt, srvy_type , srvy_trgt, nm_clct_yn, gndr_clct_yn, inst_clct_yn , mpno_clct_yn, eml_clct_yn, addr_clct_yn , srvy_cn, atch_file_use_yn, atch1_file_ttl, atch1_file_oid , atch2_file_ttl, atch2_file_oid , CASE WHEN srvy_stts = 'DEL' THEN '미사용' ELSE '사용' END AS srvy_stts , rspns_cnt, reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.srvy
AND srvy_oid = #{srvyOid}
ORDER BY srvy_oid DESC

/* selectUserOptList */ SELECT srvy_qitem_opt_oid, srvy_qitem_oid, srvy_qitem_opt_seq, srvy_qitem_opt_txt , srvy_qitem_opt_img_file_oid, etc_opt_yn, rspns_cnt , reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.srvy_qitem_opt WHERE srvy_qitem_oid IN
#{srvyQitemOid}
ORDER BY srvy_qitem_opt_seq

mapper.insert:
/* insertSurveyResp */
INSERT INTO ${schema}.srvy_rspns (
      srvy_rspdnt_oid, srvy_qitem_oid, srvy_qitem_opt_oid
    , srvy_rspns_txt, srvy_rspns_no , srvy_rspns_rank
    , srvy_rspns_file_no
    , reg_id, reg_dt, mdfcn_id, mdfcn_dt
)
VALUES (
      #{srvyRspdntOid}, #{srvyQitemOid}, #{srvyQitemOptOid}, #{srvyRspnsTxt}
    , #{srvyRspnsNo}, #{srvyRspnsRank}, #{srvyRspnsFileNo}
    , #{regId}, now(), #{mdfcnId}, now()
)
